import { useState, useEffect, useCallback } from "react";
import type {
  FormatInfo,
  ToolInfo,
  FlowInfo,
  PluginInfo,
  ProjectInfo,
  BlockInfo,
  UpdateBlockRequest,
  UpdateBlockTargetCodedRequest,
  AITranslateFileRequest,
  TranslationStats,
  WordCountResult,
  ProviderConfig,
  ProviderConfigWithKey,
} from "../types/api";

// Wails v3 bindings – ES module imports generated by `wails3 generate bindings`.
// eslint-disable-next-line @typescript-eslint/ban-ts-comment
// @ts-ignore – generated .js bindings outside the TS project root
import * as Backend from "../../bindings/github.com/gokapi/gokapi/apps/bowrain/backend/app.js";


export function useFormats() {
  const [formats, setFormats] = useState<FormatInfo[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    Backend.ListFormats()
      .then((r: FormatInfo[]) => setFormats(r))
      .catch((e: Error) => setError(e.message))
      .finally(() => setLoading(false));
  }, []);

  return { formats, loading, error };
}

