export function usePlugins() {
  const [plugins, setPlugins] = useState<PluginInfo[]>([]);
  const [pluginDir, setPluginDir] = useState<string>("");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    Promise.all([Backend.ListPlugins(), Backend.PluginDir()])
      .then(([pl, dir]: [PluginInfo[], string]) => {
        setPlugins(pl);
        setPluginDir(dir);
      })
      .catch((e: Error) => setError(e.message))
      .finally(() => setLoading(false));
  }, []);

  return { plugins, pluginDir, loading, error };
}

export function useHealth() {
  // Wails v3 bindings are always available as ES module imports.
  const connected = true;
  const refresh = useCallback(() => {}, []);
  return { connected, refresh };
}

// Project API hooks

export function useProjectApi() {
  const createProject = useCallback(
    async (name: string, sourceLang: string, targetLangs: string[]): Promise<ProjectInfo> => {
      return Backend.CreateProject(name, sourceLang, targetLangs) as Promise<ProjectInfo>;
    },
    [],
  );

  const listProjects = useCallback(async (): Promise<ProjectInfo[]> => {
    return Backend.ListProjects() as Promise<ProjectInfo[]>;
  }, []);

  const openProject = useCallback(
    async (path: string): Promise<ProjectInfo> => {
      return Backend.OpenProject(path) as Promise<ProjectInfo>;
    },
    [],
  );

  const openProjectDialog = useCallback(
    async (): Promise<ProjectInfo | null> => {
      return Backend.OpenProjectDialog() as Promise<ProjectInfo | null>;
    },
    [],
  );

  const saveProjectDialog = useCallback(
    async (projectID: string): Promise<void> => {
      return Backend.SaveProjectDialog(projectID);
    },
    [],
  );

  const closeProject = useCallback(
    async (projectID: string): Promise<void> => {
      return Backend.CloseProject(projectID);
    },
    [],
  );

  const addFiles = useCallback(
    async (projectID: string, filePaths: string[]): Promise<ProjectInfo> => {
      return Backend.AddFiles(projectID, filePaths) as Promise<ProjectInfo>;
    },
    [],
  );

  const removeFile = useCallback(
    async (projectID: string, fileName: string): Promise<ProjectInfo> => {
      return Backend.RemoveFile(projectID, fileName) as Promise<ProjectInfo>;
    },
    [],
  );

  const saveProject = useCallback(
    async (projectID: string): Promise<void> => {
      return Backend.SaveProject(projectID);
    },
    [],
  );

  const saveProjectAs = useCallback(
    async (projectID: string, path: string): Promise<void> => {
      return Backend.SaveProjectAs(projectID, path);
    },
    [],
  );

  const addFilesDialog = useCallback(
    async (projectID: string): Promise<ProjectInfo | null> => {
      return Backend.AddFilesDialog(projectID) as Promise<ProjectInfo | null>;
    },
    [],
  );

  return {
    createProject,
    listProjects,
    openProject,
    openProjectDialog,
    saveProjectDialog,
    closeProject,
    addFiles,
    removeFile,
    saveProject,
    saveProjectAs,
    addFilesDialog,
  };
}

